@use "../../styles/theme.scss";
@use "../../styles/mixins.scss";

.container {
  @include mixins.flexCenter;
  position: relative;
  border-radius: theme.$border-radius-medium;
  border: 3px solid transparent;
  width: 100%;
  height: 100%;
  overflow: hidden;
  transition: border-color 0.3s ease;

  &.speaking {
    border-color: theme.$color-info;
    box-shadow: 0 0 8px rgba(theme.$color-info, 0.5);
  }
}

.video {
  object-fit: cover;
  height: 100%;
  width: auto;
  transition: opacity 0.3s ease-out;

  &.widthProportion {
    width: 100%;
    height: auto;
  }

  &.heightProportion {
    width: auto;
    height: 100%;
  }
}

.noVideo {
  @include mixins.flexCenter;
  background-color: rgba(theme.$color-dark-primary, 80%);
  color: theme.$color-text-secondary;
  font-size: 1.4rem;
  font-weight: 500;
}

.userInfo {
  @include mixins.flex(row, flex-start, center);
  width: max-content;
  column-gap: 1.5rem;
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  padding: 0.5rem;

  color: theme.$color-text-tertiary;
  margin-left: 1rem;
  margin-bottom: 1rem;
  border-radius: theme.$border-radius;
  background-color: rgba(theme.$color-dark-primary, 50%);

  z-index: 10;
}

.menuContainer {
  position: absolute;
  top: 5px;
  right: 8px;
  z-index: 100;
}

.menu {
  font-size: 3rem;
  color: theme.$color-text-secondary;
  rotate: 90deg;
  cursor: pointer;
}

.gmLabel {
  position: absolute;
  top: 10px;
  right: 10px;
  z-index: 10;

  color: theme.$color-accent-secondary;
}

.statusIconsContainer {
  @include mixins.flex(row, flex-start, center);
  column-gap: 1.5rem;
  position: absolute;
  bottom: 10px;
  right: 10px;
  font-size: 2rem;
  color: theme.$color-text-primary;

  z-index: 10;
}

.statusIcon {
  cursor: pointer;
}

.statusDisabled {
  color: theme.$color-error;
}

.deadOverlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;

  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;

  border: 2px solid theme.$color-dark-secondary;
  border-radius: theme.$border-radius;
  z-index: 10;

  animation: deadFadeIn 0.5s ease-out forwards;
}

@keyframes deadFadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes mafiaGlow {
  0%,
  100% {
    box-shadow: 0 0 4px 1px rgba(theme.$color-error, 0.15);
  }
  50% {
    box-shadow:
      0 0 20px 5px rgba(theme.$color-error, 0.55),
      0 0 0 2px rgba(theme.$color-error, 0.85);
  }
}

.mafiaGlow {
  animation: mafiaGlow 3s ease-in-out infinite;
}

.gmIconContainer {
  position: absolute;
  top: 10px;
  left: 10px;
  z-index: 1;
}

.prostituteOverlay {
  @include mixins.flexCenter;

  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(theme.$color-role-prostitute, 0.2);
  border: 2px solid theme.$color-role-prostitute;
  border-radius: theme.$border-radius;

  color: theme.$color-role-prostitute;
  font-size: 5rem;
  z-index: 9;
}

.shootable {
  /* noinspection CssUnknownTarget */
  cursor:
    url("/aim.svg") 16 16,
    crosshair !important;
  transition: box-shadow 0.2s;

  &:hover {
    box-shadow: inset 0 0 20px rgba(theme.$color-error, 0.4);
  }
}

.kissable {
  /* noinspection CssUnknownTarget */
  cursor:
    url("/kiss.svg") 16 16,
    pointer !important;
  transition: box-shadow 0.2s;

  &:hover {
    box-shadow: inset 0 0 20px rgba(theme.$color-role-prostitute, 0.4);
  }
}

.healable {
  /* noinspection CssUnknownTarget */
  cursor:
    url("/syringe.svg") 16 16,
    pointer !important;
}

.checkable {
  /* noinspection CssUnknownTarget */
  cursor:
    url("/question.svg") 16 16,
    help !important;
  transition: box-shadow 0.2s;

  &:hover {
    box-shadow: inset 0 0 20px rgba(theme.$color-accent-secondary, 0.4);
  }
}
.statusLabelDead {
  @include mixins.flexCenter;
  padding: 4px 8px;

  position: absolute;
  top: 10px;
  left: 10px;

  background-color: theme.$color-error;
  color: theme.$color-text-primary;
  border-radius: 4px;

  font-size: 1.2rem;
  font-weight: 700;
  text-transform: uppercase;

  z-index: 20;
}

